using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Newtonsoft.Json;
using Azure.Functions.Worker.Http;

namespace ReportingApiFunctionApp
{
    public static class QueryDatabase
    {
        private const string ConnectionString = "<your_connection_string>";

        [Function("QueryDatabase")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = "query")] HttpRequestData req,
            ILogger log)
        {
            var queryString = req.Query.ToString();
            using (var connection = new SqlConnection(ConnectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(queryString, connection))
                {
                    var result = await command.ExecuteReaderAsync();
                    var output = new List<dynamic>();
                    while (await result.ReadAsync())
                    {
                        output.Add(result);
                    }
                    return new OkObjectResult(output);
                }
            }
        }
    }
